#import "TPSettingsPageDetector.h"
@implementation TPSettingsPageDetector
+(void)findTables:(UIView*)v into:(NSMutableArray*)a{if([v isKindOfClass:UITableView.class])[a addObject:v];for(UIView*s in v.subviews)[self findTables:s into:a];}
+(void)collectText:(UIView*)v into:(NSMutableString*)s{if([v isKindOfClass:UILabel.class]&&((UILabel*)v).text.length)[s appendFormat:@" %@",((UILabel*)v).text.lowercaseString];for(UIView*x in v.subviews)[self collectText:x into:s];}
+(UITableView*)settingsTableInController:(UIViewController*)vc{if(!vc.view.window)return nil;UITabBarController*tab=vc.tabBarController;if(tab&&tab.selectedIndex+1<tab.viewControllers.count)return nil;NSMutableArray*tables=[NSMutableArray array];[self findTables:vc.view into:tables];NSString*className=NSStringFromClass(vc.class).lowercaseString;for(UITableView*t in tables){if(t.hidden||!t.window)continue;NSInteger rows=0;for(NSInteger s=0;s<[t numberOfSections];s++)rows+=[t numberOfRowsInSection:s];if(rows<4)continue;NSMutableString*text=[NSMutableString string];[self collectText:t into:text];NSInteger hits=0;for(NSString*k in @[@"account",@"privacy",@"notifications",@"storage",@"help",@"账号",@"隐私",@"通知",@"存储",@"帮助"])if([text containsString:k])hits++;BOOL structural=tab&&tab.selectedIndex==tab.viewControllers.count-1;BOOL named=[className containsString:@"setting"]||[className containsString:@"profile"];if((structural||named)&&hits>=2)return t;}return nil;}
@end
